def find_period_1d_v2(seq, max_errors=3):
    """Find smallest period with at most max_errors mismatches."""
    n = len(seq)

    for p in range(1, n // 2 + 1):
        if n < 2 * p:
            break
        tile = []
        for i in range(p):
            vals = [seq[j] for j in range(i, n, p)]
            tile.append(Counter(vals).most_common(1)[0][0])
        errors = sum(1 for i in range(n) if seq[i] != tile[i % p])

        if errors <= max_errors:
            return (errors, p, tile)

    return None

