def find_regions(grid):
    import numpy as np
    from collections import Counter

    grid = np.array(grid)
    H, W = grid.shape

    # Find background color
    border = list(grid[0]) + list(grid[-1]) + list(grid[1:-1, 0]) + list(grid[1:-1, -1])
    bg = Counter(border).most_common(1)[0][0]

    # Find frame color (first non-bg color going inward)
    frame_color = None
    for r in range(H):
        for c in range(W):
            if grid[r, c] != bg:
                frame_color = grid[r, c]
                break
        if frame_color is not None:
            break

    structural = {bg, frame_color}

    # Separator row: all cells are bg or frame
    sep_rows = [r for r in range(H) if all(grid[r, c] in structural for c in range(W))]
    sep_cols = [c for c in range(W) if all(grid[r, c] in structural for r in range(H))]

    # Find content regions between separators
    regions = []
    for i in range(len(sep_rows)):
        for j in range(i + 1, len(sep_rows)):
            r1, r2 = sep_rows[i], sep_rows[j]
            if r2 - r1 <= 1:
                continue
            if any(r1 < r < r2 for r in sep_rows):
                continue
            for k in range(len(sep_cols)):
                for l in range(k + 1, len(sep_cols)):
                    c1, c2 = sep_cols[k], sep_cols[l]
                    if c2 - c1 <= 1:
                        continue
                    if any(c1 < c < c2 for c in sep_cols):
                        continue
                    regions.append((r1 + 1, r2, c1 + 1, c2))

    return regions, int(bg), int(frame_color)

