def find_2d_tile(data, max_errors=5):
    """Find smallest 2D repeating tile for data array."""
    h, w = data.shape
    best = None  # (errors, pr, pc, tile)

    for pr in range(1, h // 2 + 1):
        for pc in range(1, w // 2 + 1):
            # Compute tile by majority voting
            tile = np.zeros((pr, pc), dtype=int)
            for r in range(pr):
                for c in range(pc):
                    vals = []
                    for i in range(r, h, pr):
                        for j in range(c, w, pc):
                            vals.append(data[i, j])
                    tile[r, c] = Counter(vals).most_common(1)[0][0]

            # Count errors
            errors = 0
            for i in range(h):
                for j in range(w):
                    if data[i, j] != tile[i % pr, j % pc]:
                        errors += 1

            if errors <= max_errors:
                if best is None or errors < best[0] or (errors == best[0] and pr * pc < best[1] * best[2]):
                    best = (errors, pr, pc, tile.copy())
                if errors == 0:
                    return best

    return best

